#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10;
struct Seg{int l,r,sum;}t[N*25];int cnt;
void build(int l,int r,int &cur)
{
//	printf("%d %d\n",l,r);
	cur=++cnt;if(l==r){return;}int mid=(l+r)>>1;
	if(l<=mid)build(l,mid,t[cur].l);if(r>mid)build(mid+1,r,t[cur].r);
}
void add(int l,int r,int cur,int &x,int pos)
{
	t[x=++cnt]=t[cur];t[x].sum++;if(l==r)return;
	int mid=(l+r)>>1;if(pos<=mid)add(l,mid,t[cur].l,t[x].l,pos);if(pos>mid)add(mid+1,r,t[cur].r,t[x].r,pos);
}
int Qry(int l,int r,int tl,int tr,int ql,int qr)
{
//	printf("%d %d %d %d\n",l,r,t[]);
	if(ql<=l&&r<=qr)return t[tr].sum-t[tl].sum;int res=0,mid=(l+r)>>1;
	if(ql<=mid)res+=Qry(l,mid,t[tl].l,t[tr].l,ql,qr);if(qr>mid)res+=Qry(mid+1,r,t[tl].r,t[tr].r,ql,qr);return res;
}
int lst,n;inline int F(int k){return (k-1+lst)%n+1;}
int a[N],b[N],pos[N],Rt[N];
inline void debug(){puts("");rep(1,cnt,i)printf("%d : %d %d %d\n",i,t[i].l,t[i].r,t[i].sum);puts("");}
int main()
{
	n=read();rep(1,n,i)pos[a[i]=read()]=i;rep(1,n,i)b[i]=pos[read()];
//	rep(1,n,i)printf("%d ",b[i]);puts("");
	build(1,n,Rt[0]);rep(1,n,i)add(1,n,Rt[i-1],Rt[i],b[i]);//debug();
	int Q=read();rep(1,Q,i)
	{
		int A=F(read()),B=F(read()),C=F(read()),D=F(read());
		int l1=min(A,B),r1=max(A,B),l2=min(C,D),r2=max(C,D);
//		printf("%d %d %d %d\n",l1,r1,l2,r2);
		printf("%d\n",lst=Qry(1,n,Rt[l2-1],Rt[r2],l1,r1));++lst;
	}
}
